  ('judicial-cf446b4c-moex-00434', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲手持名牌皮包行經路口，乙騎乘機車，自甲後方快速扯走其名牌皮包，揚長而去。甲之刑事責任為何？', '["搶奪罪", "強盜罪", "強制罪", "詐欺罪"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 42, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00435', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '深夜，甲持刀喝令乙女交出錢財，否則將對之不利，乙女驚嚇癱軟在地無法動彈，只能將身上財物全數交 出。關於甲之行為，下列敘述何者正確？', '["成立搶奪罪", "成立強盜取財罪", "成立加重詐欺罪", "成立加重恐嚇取財罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00436', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '工人甲與同事乙發生爭吵，遂於工地以傷害故意追打乙，在追逐過程中，甲把乙打傷倒地，乙頭部因而撞 擊水泥地面而死亡。依實務見解，甲成立何罪？', '["殺人罪", "傷害致死罪", "過失致死罪", "過失傷害致死罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00437', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於罪刑法定原則，下列敘述何者錯誤？', '["刑法所規定的犯罪要件與法律效果應力求具體明確", "沒收適用裁判時之法律", "強制工作並非刑罰，故無須受到罪刑法定原則之拘束", "習慣法不得作為論罪科刑之依據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00438', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲與乙有消費糾紛，乃持槍前往乙宅理論；乙在家中，但拒不出面，甲盛怒之下，朝乙宅開槍掃射，乙當 場死亡。關於甲之行為，下列敘述何者正確？', '["強盜致死罪", "過失致死罪", "普通殺人罪", "義憤殺人罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00439', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於過失致死罪之敘述，下列何者正確？', '["我國刑法現有業務過失致死加重處罰之規定", "我國刑法現有重大過失致死加重處罰之規定", "我國刑法現僅有普通過失致死罪之規定", "我國刑法現有輕率過失致死加重處罰之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00440', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲父在乙女小時候，對乙多次為強制性交行為。乙成年後，甲因病陷於無自救能力狀態，乙竟拒絕對甲為 生存所必要之扶助及保護。有關乙之刑責，下列敘述何者正確？', '["乙依據刑法第293條無義務遺棄罪處罰", "乙依據刑法第294條有義務遺棄罪處罰", "乙依據刑法第295條遺棄直系血親尊親屬罪處罰", "乙依據刑法第294條之1不罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00441', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '基金會董事長甲不滿董事乙之作風，甲在基金會之官方網頁上，公然謊稱「乙董事侵占公款」。甲成立何罪？', '["刑法第309條第1項之公然侮辱罪", "刑法第310條第1項之普通誹謗罪", "刑法第310條第2項之加重誹謗罪", "刑法第309條第2項之強暴侮辱罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00442', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲與乙分手後，從前女友乙之日記中得知其帳號密碼，遂上網登入乙電子郵件，閱讀乙之信件，甲成立何罪？', '["刑法第358條之無故入侵電腦罪", "刑法第359條之變更他人電磁紀錄罪", "刑法第360條干擾他人電腦罪", "刑法第315條之1窺視竊錄非公開言論談話罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:24+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00443', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-110-f335c5ad', 'sub-judicial-cf446b4c-02', NULL, 'essay', '債權人甲對債務人乙取得新臺幣（下同）500萬元勝訴之確定終局判決
